ay","required":false,"description":"Source identifiers supporting this step","items":{"type":"string"}}]}},{"name":"emotional_arc","type":"object","required":true,"description":"Emotional arc — drives tone from opening to close","fields":[{"name":"opening_emotion","type":"string","required":true,"description":"How the reader arrives (e.g., confusion, frustration, curiosity)"},{"name":"turning_point","type":"string","required":true,"description":"The moment of insight (e.g., clarity, surprise)"},{"name":"closing_emotion","type":"string","required":true,"description":"How the reader leaves (e.g., confidence, motivation, relief)"}]},{"name":"key_stats","type":"array","required":false,"description":"Verified statistics — embed in the H2 matching their argument_chain step","items":{"type":"object","fields":[{"name":"stat","type":"string","required":true,"description":"Brief description of what the statistic measures"},{"name":"figure","type":"string","required":true,"description":"The actual number or percentage"},{"name":"source_id","type":"string","required":true,"description":"Links to source ID"}]}},{"name":"key_quotes","type":"array","required":false,"description":"Expert quotes — format as pull quotes with attribution (optional)","items":{"type":"object","fields":[{"name":"quote","type":"string","required":true,"description":"The actual quote"},{"name":"author","type":"string","required":true,"description":"Who said it"},{"name":"credentials","type":"string","required":true,"description":"Their authority or credentials"}]}},{"name":"affiliate_context","type":"object","required":false,"description":"Affiliate placement — optional","fields":[{"name":"trigger_context","type":"string","required":true,"description":"Which argument_chain step this follows"},{"name":"product_angle","type":"string","required":true,"description":"How the product solves the revealed problem"},{"name":"cta_primary","type":"string","required":true,"description":"Exact CTA text"}]},{"name":"cta