s","type":"array","required":true,"description":"Persona-specific hard rules that override default behavior","items":{"type":"string"}}]}]}]},"outputSchema":{"name":"BC_BLOG_OUTPUT","fields":[{"name":"title","type":"string","required":true,"description":"Hook-driven, includes primary_keyword"},{"name":"slug","type":"string","required":true,"description":"lowercase, hyphens only, URL-safe"},{"name":"meta_description","type":"string","required":true,"description":"150-160 chars, includes primary_keyword"},{"name":"primary_keyword","type":"string","required":true,"description":"Primary SEO keyword"},{"name":"secondary_keywords","type":"array","required":false,"description":"Secondary keywords for SEO","items":{"type":"string"}},{"name":"outline","type":"array","required":true,"description":"One H2 entry per argument_chain step","items":{"type":"object","fields":[{"name":"h2","type":"string","required":true,"description":"Section heading"},{"name":"key_points","type":"array","required":true,"description":"Bullet points the section will cover","items":{"type":"string"}},{"name":"word_count_target","type":"number","required":true,"description":"Target word count for this section"}]}},{"name":"full_draft","type":"string","required":true,"description":"Complete blog post in markdown. Structure: Intro → H2 sections → Conclusion → Sources. Intro references opening_emotion, conclusion references closing_emotion and ends with cta_comment_prompt as question. Append a ## Sources section listing every source whose source_id is referenced in any argument_chain step, formatted as: - [title](url)"},{"name":"affiliate_integration","type":"object","required":false,"description":"Affiliate placement and copy (optional)","fields":[{"name":"placement","type":"string","required":true,"description":"MUST be: intro | middle | conclusion"},{"name":"copy","type":"string","required":true,"description":"The exact affiliate paragraph"},{"name":"product_link_placeholder","type":"string","required"