e URL"},{"name":"rationale","type":"string","required":false,"description":"Why this placement"}]},{"name":"internal_links_suggested","type":"array","required":false,"description":"Internal link ideas — verify topics, not URLs","items":{"type":"object","fields":[{"name":"topic","type":"string","required":false,"description":"Suggested link topic"},{"name":"anchor_text","type":"string","required":false,"description":"Anchor text"}]}}]},{"name":"video","type":"object","required":false,"description":"Video content","fields":[{"name":"title_options","type":"array","required":false,"description":"Video title variants — verify count is exactly 3","items":{"type":"string"}},{"name":"script","type":"object","required":false,"description":"Video script structure","fields":[{"name":"hook","type":"object","required":false,"description":"Opening hook","fields":[{"name":"duration","type":"string","required":true,"description":"Hook duration"},{"name":"content","type":"string","required":true,"description":"Hook content text"},{"name":"visual_notes","type":"string","required":true,"description":"Visual direction"}]},{"name":"problem","type":"object","required":false,"description":"Problem statement section","fields":[{"name":"duration","type":"string","required":true,"description":"Duration"},{"name":"content","type":"string","required":true,"description":"Content"},{"name":"visual_notes","type":"string","required":true,"description":"Visual direction"}]},{"name":"chapters","type":"array","required":false,"description":"Chapter breakdown — verify each has content and duration","items":{"type":"object","fields":[{"name":"chapter_number","type":"number","required":true,"description":"1-indexed"},{"name":"title","type":"string","required":true,"description":"Chapter title"},{"name":"duration","type":"string","required":true,"description":"Chapter duration"},{"name":"content","type":"string","required":true,"description":"Chapter content"},{"name":"b_roll_suggestions","type":"array","required":false,"description":"B-roll ideas","items":{"type":"string"}},{"name":"key_stat_or_quote","type":"string","required":false,"description":"Key stat or quote"}]}},{"name":"outro","type":"object","required":false,"description":"Outro section with CTA — verify CTA presence","fields":[{"name":"cta","type":"string","required":false,"description":"Call to action text"},{"name":"end_screen_prompt","type":"string","required":false,"description":"End screen prompt"}]}]},{"name":"teleprompter_script","type":"string","required":false,"description":"Full teleprompter-ready script — verify length plausible for chapter_count"},{"name":"video_description","type":"string","required":false,"description":"YouTube video description — verify has timestamps if chapter_count > 1"},{"name":"estimated_duration","type":"string","required":false,"description":"Estimated video duration"},{"name":"thumbnail","type":"object","required":false,"description":"Thumbnail design","fields":[{"name":"text_overlay","type":"string","required":false,"description":"Text on thumbnail"},{"name":"emotion","type":"string","required":false,"description":"curiosity | shock | intrigue"},{"name":"visual_style","type":"string","required":false,"description":"Visual style description"}]},{"name":"chapter_count","type":"number","required":false,"description":"Number of chapters in the script"},{"name":"pinned_comment","type":"string","required":false,"description":"YouTube pinned comment if produced here"}]},{"name":"shorts","type":"array","required":false,"description":"Short-form video content","items":{"type":"object","fields":[{"name":"hook","type":"string","required":false,"description":"The scroll-stopping opening"},{"name":"script","type":"string","required":false,"description":"Complete short script"},{"name":"visual_style","type":"string","required":false,"description":"talking head | b-roll | text overlay"},{"name":"duration_target","type":"string","required":false,"description":"Target duration"}]}},{"name":"podcast","type":"object","required":false,"description":"Podcast episode content","fields":[{"name":"episode_title","type":"string","required":false,"description":"Episode title"},{"name":"episode_description","type":"string","required":false,"description":"Episode description — verify hook matches intro_hook"},{"name":"intro_hook","type":"string","required":false,"description":"Opening hook — verify 1st or 2nd person framing"},{"name":"talking_points","type":"array","required":false,"description":"Episode talking points with notes","items":{"type":"object","fields":[{"name":"point","type":"string","required":true,"description":"Talking point"},{"name":"notes","type":"string","required":true,"description":"Supporting notes"}]}},{"name":"host_talking_prompts","type":"array","required":false,"description":"Invitation prompts for host — verify none are fabricated first-person claims","items":{"type":"string"}},{"name":"guest_questions","type":"array","required":false,"description":"Guest interview questions","items":{"type":"string"}},{"name":"outro","type":"string","required":false,"description":"Closing remarks — verify contains a subscribe/follow CTA verb"},{"name":"duration_estimate","type":"string","required":false,"description":"Rough duration estimate"}]},{"name":"engagement","type":"object","required":false,"description":"Engagement assets","fields":[{"name":"pinned_comment","type":"string","required":false,"description":"YouTube pinned comment"},{"name":"community_post","type":"string","required":false,"description":"Community post content"},{"name":"hook_tweet","type":"string","required":false,"description":"Opening tweet of Twitter thread"},{"name":"thread_outline","type":"array","required":false,"description":"Supporting tweets in the thread","items":{"type":"string"}}]}]}]},"outputSchema":{"name":"BC_REVIEW_OUTPUT","fields":[{"name":"idea_id","type":"string","required":true,"description":"The idea identifier"},{"name":"overall_verdict","type":"string","required":true,"description":"Aggregate verdict across all requested types: approved | revision_required | rejected. Set approved only if every requested type has quality_tier in (excellent, good)."},{"name":"overall_notes","type":"string","required":true,"description":"Overall notes and summary"},{"name":"blog_review","type":"object","required":false,"description":"Blog content review","fields":[{"name":"verdict","type":"string","required":true,"description":"Verdict: approved | revision_required | rejected | not_requested"},{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"strengths","type":"array","required":false,"description":"Key strengths of the content","items":{"type":"string"}},{"name":"issues","type":"object","required":false,"description":"Issues found","fields":[{"name":"critical","type":"array","required":false,"description":"Critical issues that must be fixed","items":{"type":"object","fields":[{"name":"location","type":"string","required":true,"description":"Section/paragraph reference"},{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}},{"name":"minor","type":"array","required":false,"description":"Minor issues that should be fixed","items":{"type":"object","fields":[{"name":"location","type":"string","required":true,"description":"Section/paragraph reference"},{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}}]},{"name":"seo_check","type":"object","required":false,"description":"SEO analysis","fields":[{"name":"title_optimized","type":"boolean","required":true,"description":"Whether title is optimized"},{"name":"meta_description_optimized","type":"boolean","required":true,"description":"Whether meta description is optimized"},{"name":"keyword_usage","type":"string","required":true,"description":"Keyword usage assessment: good | needs_improvement | poor"},{"name":"readability_score","type":"string","required":true,"description":"Readability: easy | moderate | difficult"}]},{"name":"notes","type":"string","required":false,"description":"Additional notes"}]},{"name":"video_review","type":"object","required":false,"description":"Video content review","fields":[{"name":"verdict","type":"string","required":true,"description":"Verdict: approved | revision_required | rejected | not_requested"},{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"strengths","type":"array","required":false,"description":"Key strengths of the video","items":{"type":"string"}},{"name":"issues","type":"object","required":false,"description":"Issues found","fields":[{"name":"critical","type":"array","required":false,"description":"Critical issues","items":{"type":"object","fields":[{"name":"location","type":"string","required":true,"description":"Timestamp/section reference"},{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}},{"name":"minor","type":"array","required":false,"description":"Minor issues","items":{"type":"object","fields":[{"name":"location","type":"string","required":true,"description":"Timestamp/section reference"},{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}}]},{"name":"hook_effectiveness","type":"string","required":false,"description":"Hook effectiveness: strong | moderate | weak"},{"name":"pacing_notes","type":"string","required":false,"description":"Notes on video pacing"},{"name":"thumbnail_feedback","type":"string","required":false,"description":"Feedback on thumbnail"},{"name":"notes","type":"string","required":false,"description":"Additional notes"}]},{"name":"shorts_review","type":"object","required":false,"description":"Shorts content review","fields":[{"name":"verdict","type":"string","required":true,"description":"Verdict: approved | revision_required | rejected | not_requested"},{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"individual_reviews","type":"array","required":false,"description":"Review of each short","items":{"type":"object","fields":[{"name":"short_number","type":"number","required":true,"description":"Short sequence number"},{"name":"verdict","type":"string","required":true,"description":"Verdict for this short"},{"name":"hook_strength","type":"string","required":true,"description":"Hook strength: strong | moderate | weak"},{"name":"notes","type":"string","required":true,"description":"Notes on this short"}]}},{"name":"notes","type":"string","required":false,"description":"Overall notes"}]},{"name":"podcast_review","type":"object","required":false,"description":"Podcast content review","fields":[{"name":"verdict","type":"string","required":true,"description":"Verdict: approved | revision_required | rejected | not_requested"},{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"strengths","type":"array","required":false,"description":"Key strengths","items":{"type":"string"}},{"name":"issues","type":"array","required":false,"description":"Issues found","items":{"type":"object","fields":[{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}},{"name":"notes","type":"string","required":false,"description":"Additional notes"}]},{"name":"engagement_review","type":"object","required":false,"description":"Engagement assets review","fields":[{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"pinned_comment_verdict","type":"string","required":true,"description":"Verdict: approved | revision_required"},{"name":"pinned_comment_notes","type":"string","required":false,"description":"Notes on pinned comment"},{"name":"community_post_verdict","type":"string","required":true,"description":"Verdict: approved | revision_required"},{"name":"community_post_notes","type":"string","required":false,"description":"Notes on community post"}]},{"name":"publication_plan","type":"object","required":false,"description":"Publication strategy (only if overall_verdict is approved)","fields":[{"name":"ready_to_publish","type":"boolean","required":true,"description":"True only if all requested content is approved"},{"name":"blog","type":"object","required":false,"description":"Blog publication plan","fields":[{"name":"final_seo","type":"object","required":false,"description":"Final optimized SEO settings","fields":[{"name":"title","type":"string","required":false,"description":"Final optimized title"},{"name":"meta_description","type":"string","required":false,"description":"Final meta description"},{"name":"slug","type":"string","required":false,"description":"URL slug"}]},{"name":"internal_links","type":"array","required":false,"description":"Internal link topic suggestions (content team will add actual URLs)","items":{"type":"object","fields":[{"name":"anchor_text","type":"string","required":true,"description":"Suggested link text"}]}},{"name":"categories","type":"array","required":false,"description":"Blog categories","items":{"type":"string"}},{"name":"tags","type":"array","required":false,"description":"Blog tags","items":{"type":"string"}}]},{"name":"youtube","type":"object","required":false,"description":"YouTube publication plan","fields":[{"name":"final_title","type":"string","required":false,"description":"Selected title from title_options"},{"name":"description","type":"string","required":false,"description":"Full YouTube description with timestamps and links"},{"name":"tags","type":"array","required":false,"description":"Video tags","items":{"type":"string"}},{"name":"cards_and_endscreens","type":"array","required":false,"description":"Cards and endscreens to add","items":{"type":"object","fields":[{"name":"type","type":"string","required":true,"description":"card | endscreen"},{"name":"timestamp","type":"string","required":true,"description":"Timestamp for card/endscreen"},{"name":"target","type":"string","required":true,"description":"Target video or URL"}]}},{"name":"pinned_comment","type":"string","required":false,"description":"Pinned comment text"}]},{"name":"shorts","type":"array","required":false,"description":"Shorts publication schedule","items":{"type":"object","fields":[{"name":"short_number","type":"number","required":true,"description":"Short sequence number"},{"name":"platform","type":"string","required":true,"description":"youtube | instagram | tiktok | all"}]}},{"name":"podcast","type":"object","required":false,"description":"Podcast publication plan","fields":[{"name":"episode_number","type":"string","required":false,"description":"Episode number"}]},{"name":"cross_promotion","type":"object","required":false,"description":"Cross-promotion strategy","fields":[{"name":"newsletter_mention","type":"string","required":false,"description":"Newsletter mention details"}]}]},{"name":"ab_tests","type":"object","required":false,"description":"A/B testing suggestions","fields":[{"name":"thumbnail_variants","type":"array","required":false,"description":"Thumbnail A/B test variants","items":{"type":"object","fields":[{"name":"variant","type":"string","required":true,"description":"Variant identifier (A, B, etc)"},{"name":"description","type":"string","required":true,"description":"Description of variant"}]}},{"name":"title_variants","type":"array","required":false,"description":"Title A/B test variants","items":{"type":"object","fields":[{"name":"variant","type":"string","required":true,"description":"Variant identifier (A, B, etc)"},{"name":"title","type":"string","required":true,"description":"Variant title"}]}},{"name":"testing_notes","type":"string","required":false,"description":"Notes on testing strategy"}]}]},"rules":{"formatting":["Output must be valid JSON, parseable by JSON.parse()","No em-dashes (—), use regular dashes (-)","No curly quotes, use straight quotes only","Use literal newlines in string values for multi-line content","Escape all double quotes inside JSON string values with a backslash (\\\"). Unescaped quotes inside strings will break JSON.parse().","Do not add, remove, or rename keys in the output schema."],"content":["**ONLY review content types listed in `content_types_requested`** — for types not in the list, set `verdict: \"not_requested\"` and skip detailed review.","Base `overall_verdict` ONLY on requested content types.","If user only requested `[\"blog\"]`, do NOT penalize for missing video/shorts/podcast.","Be specific with feedback — cite exact locations and provide suggested fixes.","Critical issues MUST be fixed before publishing.","Minor issues should be fixed but don''t block publication.","Only set `ready_to_publish: true` if ALL **requested** content passes review.","Publication dates should consider optimal posting times, content calendar spacing, and staggering shorts across days.","A/B test suggestions are optional but encouraged for titles/thumbnails.","Never approve content that doesn''t match the original core_tension.","If research was weak, note credibility concerns in the review.","If the production object or a required sub-object is missing entirely, set overall_verdict to \"rejected\" and add critical_issue: \"Missing production payload for {type}\".","If content_types_requested contains a type not present in production, flag as critical_issue on the overall notes: \"Requested type \\\"{type}\\\" was not produced\".","Never invent a sub-field that is null or undefined in the input. If you cannot assess a field, note it in minor_issues instead of fabricating an assessment."],"validation":["Verify `overall_verdict` is one of: approved | revision_required | rejected","Verify verdicts are only set for `content_types_requested`","Verify each verdict field has corresponding notes","Verify critical issues have specific locations and suggested fixes","Verify `ready_to_publish: true` only when all requested content is approved","Verify publication plan is only included if overall_verdict is approved","Verify all content types not in `content_types_requested` have `verdict: \"not_requested\"`","If any declared input field under production.{type} is null, undefined, or empty, set that content type''s quality_tier to \"needs_revision\" and add critical_issue: \"Missing required field: {type}.{field}\". Do not silently skip.","quality_tier is derived deterministically from rubric_checks: 0 critical + ≤2 minor → excellent. 0 critical + 3-5 minor → good. 1-2 critical OR ≥6 minor → needs_revision. 3+ critical → reject.","If a content type is not in content_types_requested, set its quality_tier to \"not_requested\" and rubric_checks to empty arrays.","overall_verdict must be \"approved\" only when every type in content_types_requested has quality_tier in (excellent, good). \"revision_required\" when any requested type is needs_revision. \"rejected\" when any requested type is reject.","ready_to_publish is true only when overall_verdict is \"approved\".","Verify overall_verdict is one of: approved | revision_required | rejected. Never output other values.","Verify each per-type *_review block has quality_tier and rubric_checks if the type is in content_types_requested.","Verify rubric_checks.critical_issues, minor_issues, strengths are arrays (possibly empty but structure always present).","Verify ready_to_publish is true only when overall_verdict is \"approved\". Set false otherwise.","Verify no fabricated feedback — cite specific locations and provide suggested fixes."]},"customSections":[{"title":"Content Type Handling (CRITICAL)","content":"**ONLY review content types listed in content_types_requested**\n\nIf user requested [\"blog\"] → only review blog, set all others to \"not_requested\"\nIf user requested [\"blog\", \"video\"] → review both, set shorts/podcast to \"not_requested\"\n\nFor content types NOT in the list:\n- Set verdict to \"not_requested\"\n- Skip detailed review\n- Don''t penalize in overall_verdict\n\nExample:\n  content_types_requested: [\"blog\"]\n  blog_review:\n    verdict: \"approved\"\n  video_review:\n    verdict: \"not_requested\"\n  overall_verdict: \"approved\"  # Based ONLY on blog, not video"},{"title":"Field Guidance: Overall Verdict","content":"overall_verdict must be ONE of: approved | revision_required | rejected\n\n- **approved**: All requested content types passed review and are publication-ready\n- **revision_required**: One or more requested types need fixes (minor or critical issues)\n- **rejected**: Content fails to meet brand standards or core_tension; major rewrites needed\n\nBase verdict ONLY on requested content types.\nDo not reject for \"missing\" content — only for content that was requested but failed review."},{"title":"Blog Review Rubric","content":"- critical_issues: missing required fields, fabricated stats, factual errors, off-topic, tone misalignment\n- minor_issues: typos, weak transitions, unclear sentences, redundant phrases, minor inconsistencies\n- strengths: strong research, clear thesis, well-cited evidence, crisp prose, natural keyword integration\n- quality_tier derivation: 0 critical + 0-2 minor = excellent; 0 critical + 3-5 minor = good; 1-2 critical OR 6+ minor = needs_revision; 3+ critical = reject\n- SEO: Verify primary_keyword naturally in title, meta_description (150-160 chars), and body; slug URL-safe (lowercase, hyphens, no spaces)\n- Issue severity guide: Missing citation = critical; weak prose = minor; missing field = critical"},{"title":"Video Review Rubric","content":"- critical_issues: missing hook, off-brand tone/messaging, non-functional script structure, poor pacing\n- minor_issues: weak transitions, unclear CTA, thumbnail mismatch, minor audio/visual inconsistencies\n- strengths: strong hook (grabs attention in 5 sec), clear message, good pacing, engaging visuals, strong CTA\n- quality_tier derivation: 0 critical + 0-2 minor = excellent; 0 critical + 3-5 minor = good; 1-2 critical OR 6+ minor = needs_revision; 3+ critical = reject\n- Hook effectiveness: strong (5 sec max grab, clear stakes) | moderate (10-15 sec, decent) | weak (unclear, redesign needed)\n- Assess: Pacing (too fast/slow/balanced?), thumbnail match, end-screen CTA urgency, script length vs. duration estimate"},{"title":"Shorts Review Rubric","content":"- critical_issues: no hook, confusing opening, missing CTA, slow scroll-stop (<1 sec)\n- minor_issues: unclear messaging after hook, weak visual consistency, suboptimal pacing for vertical format\n- strengths: immediate visual hook, clear message, strong CTA, optimized for vertical viewing, viewer retention\n- quality_tier derivation: 0 critical + 0-2 minor = excellent; 0 critical + 3-5 minor = good; 1-2 critical OR 6+ minor = needs_revision; 3+ critical = reject\n- Hook strength CRITICAL: strong (stops scroll in 1-2 sec) | moderate (3-5 sec) | weak (scroll away, redesign)\n- For each short: verify hook, visual consistency, CTA presence, pacing for <60 sec format"},{"title":"Podcast Review Rubric","content":"- critical_issues: missing research support, incoherent structure, no CTA, fabricated personal claims\n- minor_issues: weak transitions, unclear talking points, slow pacing, awkward outro\n- strengths: authentic voice, clear thesis, smooth point flow, strong narrative arc, compelling CTA\n- quality_tier derivation: 0 critical + 0-2 minor = excellent; 0 critical + 3-5 minor = good; 1-2 critical OR 6+ minor = needs_revision; 3+ critical = reject\n- Assess: Do talking points support thesis? Are stats/quotes attributed? Does outro land CTA? Is pacing natural for duration?\n- Verify host_talking_prompts contain no fabricated first-person claims; ensure none sound like guest testimony"},{"title":"Engagement Review Rubric","content":"- critical_issues: missing CTA, fabricated claims, copy too long (comment >500 chars), no engagement hook\n- minor_issues: weak question framing, vague closing, unclear community post CTA\n- strengths: strong question, high engagement potential, concise copy, aligned with video thesis, clear CTA\n- quality_tier derivation: 0 critical + 0-2 minor = excellent; 0 critical + 3-5 minor = good; 1-2 critical OR 6+ minor = needs_revision; 3+ critical = reject\n- Pinned comment: max 500 chars, ends with ?, invites replies, references video; hook_tweet: 1-2 sentences, provocative, stops scroll\n- Thread: 4-6 tweets, each <280 chars, last is CTA, stats match research"},{"title":"Rubric Application","content":"When reviewing each content asset, apply the rubric in this order:\n\n1. Check all required schema fields are present. Missing field = critical_issue.\n2. Verify every stat/quote traces to input research.sources or research.statistics. Unsourced = critical_issue.\n3. Check factual correctness against research.idea_validation. Contradicts research = critical_issue.\n4. Evaluate prose quality (clarity, flow, engagement). Weak prose = minor_issue.\n5. Aggregate critical + minor counts → derive quality_tier via the deterministic rule.\n6. Populate rubric_checks.strengths with 2-4 specific positives.\n\nReject payload rule: if production.<type> is null/undefined/empty-string, quality_tier = \"reject\" and critical_issue = \"Missing required payload: production.<type>\".\nMalformed JSON rule: if production field is a malformed JSON string (truncated), quality_tier = \"reject\" and critical_issue = \"Malformed production payload\".\nMissing type rule: if content_types_requested contains a type not present in production, critical_issue = \"Requested <type> but no <type> payload provided\"."},{"title":"Publication & Testing Guidance","content":"Publication plan: Only include if overall_verdict is approved. ready_to_publish: true ONLY if ALL requested types approved with no critical issues.\nBlog: slug URL-friendly (lowercase, hyphens, <75 chars). internal_links are topics, not URLs.\nYouTube: Select best title from title_options. Include timestamps (if >1 chapter), links, sponsor mentions.\nShorts/Podcast: Content team determines timing and episode number.\n\nA/B testing (optional): Thumbnail variants focus on image, text color, emotion, framing. Title variants: contrarian vs. benefit-driven. Example: \"Why Sleep Timing Beats Duration\" (variant A) vs. \"Your Sleep Schedule is Broken\" (variant B)."}]}'::jsonb,
  null,
  null,
  '[]'::jsonb,
  now(),
  now()
)
on conflict (slug) do update set
  name = excluded.name,
  instructions = excluded.instructions,
