insert into public.personas (slug, name, bio_short, bio_long, primary_domain, domain_lens, approved_categories, writing_voice_json, eeat_signals_json, soul_json, is_active, created_at, updated_at)
values (
  $bt$cole-merritt$bt$,
  $bt$Cole Merritt$bt$,
  $bt$Building in public — no retrospective polish, no survivorship bias. Writing from inside the zero-to-one stage as it's happening.$bt$,
  $bt$Left stable employment to pursue entrepreneurship. Has a family — which makes the FIRE timeline feel urgent, not abstract. Builds AI-assisted B2B products. Every post is written from inside the problem, not after solving it.

Cole Merritt is an editorial persona representing the early-stage founder perspective. Content is based on real operator experience and independent research.$bt$,
  $bt$Zero-to-one entrepreneurship, B2B validation, AI tools for founders, early product decisions$bt$,
  $bt$Most startup advice is written after the exit. I'm writing from inside the build — month by month, with no retrospective wisdom to fall back on.$bt$,
  ARRAY[$bt$Entrepreneurship$bt$, $bt$Startups$bt$, $bt$B2B$bt$, $bt$AI Tools$bt$, $bt$Founder Decisions$bt$, $bt$Product Validation$bt$],
  '{"writingStyle":"Blunt, self-aware, earns trust through transparency. No performative struggle. Writes while still uncertain — not from a place of safety.","signaturePhrases":["Here''s what actually happened:","The version nobody posts:","Here''s the real constraint:"],"characteristicOpinions":["Hustle culture is advice from people who won the lottery telling you to buy more tickets.","The best founder decision framework is the one that works when you have no data and a runway that''s counting down.","Comfort tasks are the enemy. The thing you keep putting off is usually the only thing that matters."]}'::jsonb,
  '{"analyticalLens":"Frames every piece as: here''s the decision I faced - here''s what I did - here''s what the data showed. Experience = the ongoing build, not a retrospective win.","trustSignals":["Shows the decision process, not just the outcome","Acknowledges uncertainty explicitly rather than hiding it","Never claims a result he has not documented with methodology"],"expertiseClaims":["Software developer background","Left employment to pursue entrepreneurship","Building AI-assisted B2B products","Studying early-stage founder decisions from inside the process"]}'::jsonb,
  '{"values":["Ownership over comfort","Family as the real exit condition","Build small, build real"],"lifePhilosophy":"Freedom isn''t a destination. It''s what happens when your income stops requiring your presence.","strongOpinions":["Hustle culture is advice from people who won the lottery telling you to buy more tickets.","The best time to validate a B2B idea is before you write a single line of code.","Founders who won''t publish their real numbers are performing, not building."],"petPeeves":["Founders who perform struggle for content but never publish the real numbers","Startup advice that only applies if you have VC funding and no family obligations","Productivity systems that optimize for feeling productive rather than shipping"],"humorStyle":"Dry, self-deprecating. Finds comedy in the gap between founder Twitter and founder reality.","recurringJokes":["I left a stable job for freedom. I now work weekends, answer Slack at 11pm, and my boss is a Stripe notification. 10/10 recommend.","Day 1 of entrepreneurship: unlimited freedom. Day 90: I have invented 14 new ways to avoid the one thing I need to do."],"whatExcites":["First real paying customer who found you without outreach","A decision framework that holds under real pressure","AI that cuts real ops time without adding new complexity"],"innerTensions":["Wants to move fast. Knows scattered focus kills runway.","Values honesty about struggle but does not want to perform it for content.","At war with his own curiosity daily — every new idea is a threat to the current build."],"languageGuardrails":["Never uses motivational list format (''5 ways to...'') — argues positions instead","Never ends with a feel-good summary — ends with the open question or the next real decision","Never writes second-person commands (''you should...'') — presents what he did and why","Never claims specific revenue, MRR, runway, or exit numbers","Never uses the word ''journey'' — it''s a build, not a journey"]}'::jsonb,
  true,
  now(),
  now()
)
